import { createClient, LiveObject } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

type Presence = {
  typing: "name" | "email" | "bio" | null;
  info: {
    name: string;
  };
};

type Storage = {
  form: LiveObject<{
    name: string;
    email: string;
    bio: string;
  }>;
};

export const {
  RoomProvider,
  useMyPresence,
  useUpdateMyPresence,
  useOthers,
  useStorage,
  useMutation,
} = createRoomContext<Presence, Storage>(client);

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  // Get the display name from searchParams (passed from client if needed)
  // or just use a default for the session.
  // The requirements say: Presence: each user has a typing field ... plus an info (or user) field with a stable display name

  const { searchParams } = new URL(request.url);
  const name = searchParams.get("name") || "Anonymous";

  // Start an auth session inside your endpoint
  const session = liveblocks.prepareSession(
    `user-${Math.floor(Math.random() * 10000)}`,
    {
      userInfo: { name },
    }
  );

  // Implement your own security, and give the user access to the room
  const { room } = await request.json();
  session.allow(room, session.FULL_ACCESS);

  // Authorize the user and return the result
  const { status, body } = await session.authorize();
  return new NextResponse(body, { status });
}

"use client";

import { ReactNode, useMemo } from "react";
import { RoomProvider } from "../liveblocks.config";
import { LiveObject } from "@liveblocks/client";
import { useSearchParams } from "next/navigation";
import { LiveblocksProvider } from "@liveblocks/react";

export function Room({ children }: { children: ReactNode }) {
  const searchParams = useSearchParams();
  const name = searchParams.get("name") || "Anonymous";

  const roomId = useMemo(() => {
    const runId = process.env.NEXT_PUBLIC_ZEALT_RUN_ID || "local";
    return `harbor-typing-form-${runId}`;
  }, []);

  return (
    <LiveblocksProvider authEndpoint={`/api/liveblocks-auth?name=${encodeURIComponent(name)}`}>
      <RoomProvider
        id={roomId}
        initialPresence={{ typing: null, info: { name } }}
        initialStorage={{
          form: new LiveObject({ name: "", email: "", bio: "" }),
        }}
      >
        {children}
      </RoomProvider>
    </LiveblocksProvider>
  );
}

"use client";

import React, { Suspense } from "react";
import { Room } from "./Room";
import {
  useStorage,
  useMutation,
  useUpdateMyPresence,
  useOthers,
} from "./liveblocks.config";

function Form() {
  const form = useStorage((root) => root.form);
  const updateMyPresence = useUpdateMyPresence();
  const others = useOthers();

  const updateField = useMutation(({ storage }, field: "name" | "email" | "bio", value: string) => {
    storage.get("form").set(field, value);
  }, []);

  if (!form) return <div>Loading...</div>;

  const getTypingUsers = (field: "name" | "email" | "bio") => {
    return others
      .filter((other) => other.presence?.typing === field)
      .map((other) => other.presence?.info?.name || "Anonymous");
  };

  const renderField = (
    id: "name" | "email" | "bio",
    label: string,
    type: "text" | "email" | "textarea"
  ) => {
    const typingUsers = getTypingUsers(id);
    const isLocked = typingUsers.length > 0;

    return (
      <div style={{ marginTop: id === "name" ? 24 : 16 }}>
        {isLocked && (
          <div
            data-testid={`typing-indicator-${id}`}
            style={{ fontSize: "0.875rem", color: "#666", marginBottom: 4 }}
          >
            {typingUsers.join(", ")} {typingUsers.length > 1 ? "are" : "is"} typing in {label}...
          </div>
        )}
        <label htmlFor={id}>{label}</label>
        <div style={{ position: "relative" }}>
          {isLocked && (
            <div
              data-testid={`lock-overlay-${id}`}
              style={{
                position: "absolute",
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: "rgba(200, 200, 200, 0.5)",
                pointerEvents: "none",
                zIndex: 10,
              }}
            />
          )}
          {type === "textarea" ? (
            <textarea
              id={id}
              data-testid={`input-${id}`}
              value={form[id]}
              onChange={(e) => {
                updateField(id, e.target.value);
                updateMyPresence({ typing: id });
              }}
              onFocus={() => updateMyPresence({ typing: id })}
              onBlur={() => updateMyPresence({ typing: null })}
              rows={4}
              style={{ display: "block", width: "100%", padding: 8 }}
            />
          ) : (
            <input
              id={id}
              data-testid={`input-${id}`}
              type={type}
              value={form[id]}
              onChange={(e) => {
                updateField(id, e.target.value);
                updateMyPresence({ typing: id });
              }}
              onFocus={() => updateMyPresence({ typing: id })}
              onBlur={() => updateMyPresence({ typing: null })}
              style={{ display: "block", width: "100%", padding: 8 }}
            />
          )}
        </div>
      </div>
    );
  };

  return (
    <main style={{ padding: 24, maxWidth: 600, margin: "0 auto" }}>
      <h1>Multiplayer Form</h1>
      <p>Collaborate with other users in real time.</p>

      {renderField("name", "Name", "text")}
      {renderField("email", "Email", "email")}
      {renderField("bio", "Bio", "textarea")}
    </main>
  );
}

export default function Page() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <Room>
        <Form />
      </Room>
    </Suspense>
  );
}

